package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.BasisAardKodeExtensie;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.Looncodegroep;
import be.schaubroeck.lpb.tools.service.BasisAardKodeExtensieService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import com.google.common.collect.HashMultimap;
import com.google.common.collect.SetMultimap;
import lombok.Data;
import lombok.RequiredArgsConstructor;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

public class CachedBasisAardKodeExtensieService implements CachedService, BasisAardKodeExtensieService {

    @Autowired
    private BasisAardKodeExtensieService basisAardKodeExtensieService;

    private static final ThreadLocal<CachedBasisAardKodeExtensieBuffer> BUFFER = new ThreadLocal<>();

    public CachedBasisAardKodeExtensieService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public void clearCache() {
        getBuffer().clear();
    }

    @Override
    public Set<AardKodeExtensie> findAfgeleideLooncodesByLooncodeGroep(Looncodegroep looncodegroep) {
        TimeLogContext.getInstance().startTimeLogging("getById");
        CachedBasisAardKodeExtensieBuffer buffer = getBuffer();
        Set<AardKodeExtensie> result = buffer.findAfgeleideLooncodesByLooncodeGroep(looncodegroep);
        if (!buffer.containsKey2(looncodegroep)) {
            result = basisAardKodeExtensieService.findAfgeleideLooncodesByLooncodeGroep(looncodegroep);
            buffer.putFindAfgeleideLooncodesByLooncodeGroep(looncodegroep, result);
        } else {
            result = buffer.findAfgeleideLooncodesByLooncodeGroep(looncodegroep);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    @Override
    public Set<AardKodeExtensie> findAfgeleideLooncodesByLooncodeGroepen(Set<Looncodegroep> looncodeGroepen) {
        Set<AardKodeExtensie> loonCodes = new HashSet<>();
        for (Looncodegroep looncodeGroep : looncodeGroepen) {
            loonCodes.addAll(this.findAfgeleideLooncodesByLooncodeGroep(looncodeGroep));
        }
        return loonCodes;
    }

    @Override
    public Set<AardKodeExtensie> findAfgeleideLooncodesByBasisAardKodeExtensie(Integer aard, Integer code, Integer extensie) {
        TimeLogContext.getInstance().startTimeLogging("findAfgeleideLooncodesByBasisAardkodeExtensie");
        CachedBasisAardKodeExtensieBuffer buffer = CachedBasisAardKodeExtensieService.getBuffer();
        AardKodeExtensieKey key = new AardKodeExtensieKey(aard, code, extensie);
        Set<AardKodeExtensie> result;
        if (!buffer.containsKey1(key)) {
            result = basisAardKodeExtensieService.findAfgeleideLooncodesByBasisAardKodeExtensie(aard, code, extensie);
            buffer.putFindAfgeleideLooncodesByBasisAardkodeExtensie(key, result);
        } else {
            result = buffer.findAfgeleideLooncodesByBasisAardkodeExtensie(key);
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    private static class CachedBasisAardKodeExtensieBuffer {

        private final SetMultimap<AardKodeExtensieKey, AardKodeExtensie> aardKodeExtensieBuffer = HashMultimap.create();
        private final SetMultimap<Looncodegroep, AardKodeExtensie> looncodegroepBuffer = HashMultimap.create();


        public void putFindAfgeleideLooncodesByBasisAardkodeExtensie(AardKodeExtensieKey key, Set<AardKodeExtensie> set) {
            aardKodeExtensieBuffer.putAll(key, set);
        }

        public void putFindAfgeleideLooncodesByLooncodeGroep(Looncodegroep key, Set<AardKodeExtensie> set) {
            looncodegroepBuffer.putAll(key, set);
        }

        public boolean containsKey1(AardKodeExtensieKey key) {
            return aardKodeExtensieBuffer.containsKey(key);
        }

        public boolean containsKey2(Looncodegroep looncodegroep) {
            return looncodegroepBuffer.containsKey(looncodegroep);
        }

        public void clear() {
            aardKodeExtensieBuffer.clear();
            looncodegroepBuffer.clear();
        }

        public Set<AardKodeExtensie> findAfgeleideLooncodesByBasisAardkodeExtensie(AardKodeExtensieKey key) {
            return aardKodeExtensieBuffer.get(key);
        }


        public Set<AardKodeExtensie> findAfgeleideLooncodesByLooncodeGroep(Looncodegroep looncodegroep) {
            return looncodegroepBuffer.get(looncodegroep);
        }
    }

    private static CachedBasisAardKodeExtensieBuffer getBuffer() {
        CachedBasisAardKodeExtensieBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedBasisAardKodeExtensieBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    @RequiredArgsConstructor
    private static class AardKodeExtensieKey {

        private final int aard;
        private final int code;
        private final int extensie;

    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public BasisAardKodeExtensie create(BasisAardKodeExtensie basisAardKodeExtensie) {
        return basisAardKodeExtensieService.create(basisAardKodeExtensie);
    }

    @Override
    public void update(BasisAardKodeExtensie basisAardKodeExtensie) {
        basisAardKodeExtensieService.update(basisAardKodeExtensie);
    }

    @Override
    public void delete(BasisAardKodeExtensie basisAardKodeExtensie) {
        basisAardKodeExtensieService.delete(basisAardKodeExtensie);
    }

    @Override
    public BasisAardKodeExtensie getById(Integer id) {
        return basisAardKodeExtensieService.getById(id);
    }

    @Override
    public BasisAardKodeExtensie getById(Integer id, String fetchFields) {
        return basisAardKodeExtensieService.getById(id, fetchFields);
    }

    @Override
    public BasisAardKodeExtensie getByCriteria(CriteriaBuilder cb) {
        return basisAardKodeExtensieService.getByCriteria(cb);
    }

    @Override
    public List<BasisAardKodeExtensie> findAll() {
        return basisAardKodeExtensieService.findAll();
    }

    @Override
    public List<BasisAardKodeExtensie> findAll(String fetchFields) {
        return basisAardKodeExtensieService.findAll(fetchFields);
    }

    @Override
    public List<BasisAardKodeExtensie> findByCriteria(CriteriaBuilder cb) {
        return basisAardKodeExtensieService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return basisAardKodeExtensieService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, BasisAardKodeExtensie> cacheByCriteria(CriteriaBuilder cb) {
        return basisAardKodeExtensieService.cacheByCriteria(cb);
    }

    @Override
    public BasisAardKodeExtensie getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return basisAardKodeExtensieService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<BasisAardKodeExtensie> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return basisAardKodeExtensieService.findByCriteriaTemporalFree(cb);
    }
}
